void reduced_struct_fjac_f32(const float*x,const float*uc,float*xd,float*fx,float*fu){
  /* cf_pieces expects [theta,v,td,pd]; state x is [v,theta,td,pd] -> reorder */
  float Xr[4] = { x[1], x[0], x[2], x[3] };
  float q[27]; cf_pieces(q, Xr);
  float td=x[2];
  float Mr00=q[0],Mr01=q[2],Mr02=q[4],Mr11=q[6],Mr12=q[8],Mr22=q[10];
  float dMr00=q[1],dMr01=q[3],dMr02=q[5],dMr11=q[7],dMr12=q[9],dMr22=q[11];
  float hr0=q[12],hr1=q[13],hr2=q[14];
  #define DH(a,k) q[15 + (a) + 3*(k)]
  /* B_red (Lever B1). theta_dot row is -tau/wheel, NOT -2tau: the relative wheel-joint
     coord already carries the body-pitch reaction (G[wheel,theta_dot]=-1), so an explicit
     extra -tau double-counts it (energy-inconsistent). See firmware reduced_model.control_map_B
     / firmware/safety_cert/test_control_map_energy.py. */
  const float Br[3][2] = {{1.0f/R, 1.0f/R}, {-1.0f, -1.0f}, {Dh/R, -Dh/R}};
  float d0=Mr00, L10=Mr01/d0, L20=Mr02/d0;
  float d1=Mr11-L10*L10*d0, L21=(Mr12-L20*L10*d0)/d1;
  float d2=Mr22-L20*L20*d0-L21*L21*d1;
  #define SOLVE(r0,r1,r2,xo) do{ float y0=(r0),y1=(r1)-L10*y0,y2=(r2)-L20*y0-L21*y1; \
    float z0=y0/d0,z1=y1/d1,z2=y2/d2; xo[2]=z2; xo[1]=z1-L21*xo[2]; xo[0]=z0-L10*xo[1]-L20*xo[2]; }while(0)
  float acc[3];
  SOLVE(Br[0][0]*uc[0]+Br[0][1]*uc[1]-hr0,
        Br[1][0]*uc[0]+Br[1][1]*uc[1]-hr1,
        Br[2][0]*uc[0]+Br[2][1]*uc[1]-hr2, acc);
  xd[0]=acc[0]; xd[1]=td; xd[2]=acc[1]; xd[3]=acc[2];
  for(int k=0;k<4;k++){
    float r0=-DH(0,k), r1=-DH(1,k), r2=-DH(2,k);
    if(k==1){ r0-=dMr00*acc[0]+dMr01*acc[1]+dMr02*acc[2];
              r1-=dMr01*acc[0]+dMr11*acc[1]+dMr12*acc[2];
              r2-=dMr02*acc[0]+dMr12*acc[1]+dMr22*acc[2]; }
    float da[3]; SOLVE(r0,r1,r2,da);
    fx[0+4*k]=da[0]; fx[1+4*k]=(k==2)?1.0f:0.0f; fx[2+4*k]=da[1]; fx[3+4*k]=da[2];
  }
  for(int j=0;j<2;j++){ float du[3]; SOLVE(Br[0][j],Br[1][j],Br[2][j],du);
    fu[0+4*j]=du[0]; fu[1+4*j]=0; fu[2+4*j]=du[1]; fu[3+4*j]=du[2]; }
  #undef SOLVE
  #undef DH
}
